// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract TokenVesting {
    address public immutable beneficiary;
    uint256 public immutable start;
    uint256 public immutable cliff;
    uint256 public immutable duration;
    uint256 public claimed;
    uint256 private _balance;

    event Deposited(address indexed from, uint256 amount);
    event Claimed(address indexed beneficiary, uint256 amount);

    error NotBeneficiary();
    error NothingToClaim();

    constructor(address _beneficiary, uint256 _start, uint256 _cliff, uint256 _duration) {
        beneficiary = _beneficiary;
        start = _start;
        cliff = _cliff;
        duration = _duration;
    }

    function deposit(uint256) external payable {
        _balance += msg.value;
        emit Deposited(msg.sender, msg.value);
    }

    function balance() public view returns (uint256) {
        return _balance;
    }

    function vestedAmount() public view returns (uint256) {
        if ([[SLOT before_cliff]]) return 0;
        uint256 total = [[SLOT total_calc]];
        if (block.timestamp >= start + duration) return total;
        uint256 elapsed = block.timestamp - start;
        return [[SLOT vested_calc]];
    }

    function claim() external {
        if (msg.sender != beneficiary) revert NotBeneficiary();
        uint256 amount = [[SLOT claimable]];
        if (amount == 0) revert NothingToClaim();
        claimed += amount;
        _balance -= amount;
        (bool ok, ) = msg.sender.call{value: amount}("");
        require(ok, "send fail");
        emit Claimed(beneficiary, amount);
    }
}
